import './TableEditableCell.scss';

import { TextField } from ':components/TextField';
import { classNames } from ':helpers/classnames';
import React, { forwardRef } from 'react';

import type { TableEditableCellProps } from './TableEditableCell.types';

export const TableEditableCell = forwardRef<HTMLInputElement, TableEditableCellProps>(
	(
		{
			alignRight = false,
			className,
			dataTestId = 'TableEditableCell',
			horizontalAlign,
			inputClassName,
			error = false,
			textFieldDataTestId,
			verticalAlign,
			wrapperClassName,
			...props
		},
		ref,
	) => {
		return (
			<td
				data-testid={dataTestId}
				className={classNames(
					'dsb_table-cell',
					'dsb_table-editable-cell',
					alignRight && !horizontalAlign && 'dsb_table-cell__horizontal-align-right',
					horizontalAlign && `dsb_table-cell__horizontal-align-${horizontalAlign}`,
					verticalAlign && `dsb_table-cell__vertical-align-${verticalAlign}`,
					className,
				)}
			>
				<TextField
					{...props}
					ref={ref}
					dataTestId={textFieldDataTestId || `${dataTestId}-field`}
					error={error}
					fullWidth
					inputClassName={classNames('dsb_table-editable-cell__input', inputClassName)}
					wrapperClassName={classNames('dsb_table-editable-cell__field', wrapperClassName)}
				/>
			</td>
		);
	},
);

TableEditableCell.displayName = 'TableEditableCell';
